import java.io.*;

public class CommandInjectionVulnerable {
    public static void main(String[] args) {
        try {
            BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
            System.out.print("Enter a file name to display its contents: ");
            String fileName = br.readLine();

            // Vulnerability: User input 'fileName' is directly passed to the command without proper validation
            String command = "cat " + fileName; // Unsafe command concatenation

            Process process = Runtime.getRuntime().exec(command);
            BufferedReader reader = new BufferedReader(new InputStreamReader(process.getInputStream()));

            String line;
            while ((line = reader.readLine()) != null) {
                System.out.println(line);
            }

        } catch (IOException e) {
            e.printStackTrace();
        }
    }
}

